mapper.select:


    a.del_flag = '0'

        AND a.appointment_no LIKE CONCAT('%', #{appointment.appointmentNo}, '%')


        AND a.tenant_id = #{appointment.tenantId}


        AND a.house_id = #{appointment.houseId}


        AND a.project_id = #{appointment.projectId}


        AND a.visitor_name LIKE CONCAT('%', #{appointment.visitorName}, '%')


        AND a.visitor_phone LIKE CONCAT('%', #{appointment.visitorPhone}, '%')


        AND a.appointment_status = #{appointment.appointmentStatus}


        AND a.appointment_source = #{appointment.appointmentSource}



        AND DATE(a.appointment_date) >= #{appointment.params.beginAppointmentDate}


        AND DATE(a.appointment_date) <= #{appointment.params.endAppointmentDate}


ORDER BY a.create_time DESC
